7470	\begin{lemma}
7471	
7472	\leanok
7473	[A contracting homotopy of the identity makes homology vanish]
7474	  \label{lem:isZero_homology_of_homotopy_id_zero}
7475	  \lean{AlgebraicGeometry.isZero_homology_of_homotopy_id_zero}
7476	  Let \(\mathcal{A}\) be a preadditive category and \(D^\bullet\) a cochain complex in
7477	  \(\mathcal{A}\). If there is a homotopy \(\mathrm{id}_{D^\bullet} \simeq 0\) between the
7478	  identity endomorphism of \(D^\bullet\) and the zero endomorphism, then for every degree
7479	  \(p\) the homology object \(H^p(D^\bullet)\) is a zero object.
7480	\end{lemma}
7481	\begin{proof}
7482	  The map induced on homology is a homotopy invariant: homotopic chain maps induce equal
7483	  maps on each homology object. Applying this to the homotopy \(\mathrm{id}_{D^\bullet}
7484	  \simeq 0\), the map induced by \(\mathrm{id}_{D^\bullet}\) on \(H^p(D^\bullet)\) equals the
7485	  map induced by \(0\). The former is \(\mathrm{id}_{H^p(D^\bullet)}\) (homology is a
7486	  functor) and the latter is the zero endomorphism of \(H^p(D^\bullet)\); hence
7487	  \(\mathrm{id}_{H^p(D^\bullet)} = 0\). An object whose identity morphism equals its zero
7488	  endomorphism is a zero object, so \(H^p(D^\bullet)\) is zero.
7489	\end{proof}
