7491	\begin{lemma}
7492	
7493	\leanok
7494	[Homology vanishes after transporting a null-homotopic complex across an isomorphism]
7495	  \label{lem:isZero_homology_of_iso_homotopy_id_zero}
7496	  \lean{AlgebraicGeometry.isZero_homology_of_iso_homotopy_id_zero}
7497	  \uses{lem:isZero_homology_of_homotopy_id_zero}
7498	  Let \(\mathcal{A}\) be a preadditive category with homology and let \(D^\bullet, D'^\bullet\) be
7499	  cochain complexes in \(\mathcal{A}\). If \(D^\bullet \cong D'^\bullet\) and \(D'^\bullet\) admits
7500	  a contracting homotopy \(\mathrm{id}_{D'^\bullet} \simeq 0\), then for every degree \(p\) the
7501	  homology \(H^p(D^\bullet)\) is a zero object. This is the consumer glue that turns the
7502	  contractibility of the model complex \(D'^\bullet\) into the vanishing of the homology of the
7503	  isomorphic complex \(D^\bullet\) actually occurring in Step~3 of
7504	  Lemma~\ref{lem:cech_augmented_resolution}.
7505	\end{lemma}
7506	\begin{proof}
7507	  \uses{lem:isZero_homology_of_homotopy_id_zero}
7508	  By Lemma~\ref{lem:isZero_homology_of_homotopy_id_zero} the null-homotopy \(\mathrm{id}_{D'^\bullet}
7509	  \simeq 0\) forces \(H^p(D'^\bullet)\) to be a zero object in every degree. Homology is a functor,
7510	  so the isomorphism \(D^\bullet \cong D'^\bullet\) induces an isomorphism \(H^p(D^\bullet) \cong
7511	  H^p(D'^\bullet)\); an object isomorphic to a zero object is itself a zero object, whence
7512	  \(H^p(D^\bullet)\) is zero.
7513	\end{proof}
